GITHUB_SEARCH_ISSUES_TOOL = {
    "name": "search_github_issues",
    "description": (
        "Search open issues in a GitHub repository by keyword. "
        "Returns id, title, url, labels, and comment count for each match. "
        "Use repo as 'owner/name', e.g. 'anthropics/anthropic-sdk-python'."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "repo": {
                "type": "string",
                "description": "Repository in owner/name format."
            },
            "query": {
                "type": "string",
                "description": "Keywords to search for in issue titles and bodies."
            },
            "limit": {
                "type": "integer",
                "description": "Maximum results to return (1–30, default 10).",
                "minimum": 1,
                "maximum": 30
            }
        },
        "required": ["repo", "query"]
    }
}

import os
import requests

GITHUB_TOKEN = os.environ["GITHUB_TOKEN"]  # never from the model
_SESSION = requests.Session()
_SESSION.headers["Authorization"] = f"Bearer {GITHUB_TOKEN}"
_SESSION.headers["Accept"] = "application/vnd.github+json"

def search_github_issues(repo: str, query: str, limit: int = 10) -> dict:
    try:
        resp = _SESSION.get(
            "https://api.github.com/search/issues",
            params={
                "q": f"{query} repo:{repo} is:issue is:open",
                "per_page": min(limit, 30),
            },
            timeout=10,
        )
    except requests.Timeout:
        return {
            "error": "SERVICE_UNAVAILABLE",
            "message": "GitHub API timed out. Try again.",
            "retryable": True,
        }

    if resp.status_code == 403:
        return {
            "error": "RATE_LIMITED",
            "message": "GitHub API rate limit reached.",
            "retryable": True,
            "retry_after": int(resp.headers.get("Retry-After", "60")),
        }
    if resp.status_code == 422:
        return {
            "error": "VALIDATION_ERROR",
            "message": f"Invalid search query: {resp.json().get('message', '')}",
            "retryable": False,
        }
    if not resp.ok:
        return {
            "error": "SERVICE_UNAVAILABLE",
            "message": f"GitHub returned HTTP {resp.status_code}.",
            "retryable": True,
        }

    data = resp.json()
    return {
        "total_count": data["total_count"],
        "results": [
            {
                "id": item["number"],
                "title": item["title"],
                "url": item["html_url"],
                "labels": [lb["name"] for lb in item["labels"]],
                "comments": item["comments"],
            }
            for item in data["items"]
        ],
    }

def create_github_issue(
    repo: str,
    title: str,
    body: str,
    labels: list | None = None,
) -> dict:
    if not title.strip():
        return {
            "error": "VALIDATION_ERROR",
            "message": "title must not be empty.",
            "retryable": False,
        }
    payload: dict = {"title": title, "body": body}
    if labels:
        payload["labels"] = labels
    try:
        resp = _SESSION.post(
            f"https://api.github.com/repos/{repo}/issues",
            json=payload,
            timeout=10,
        )
    except requests.Timeout:
        return {"error": "SERVICE_UNAVAILABLE", "message": "Timed out.", "retryable": True}
    if resp.status_code == 201:
        issue = resp.json()
        return {"id": issue["number"], "url": issue["html_url"], "title": issue["title"]}
    if resp.status_code == 403:
        return {"error": "PERMISSION_DENIED", "message": "No write access to this repo.", "retryable": False}
    return {"error": "SERVICE_UNAVAILABLE", "message": f"HTTP {resp.status_code}", "retryable": True}

import anthropic
import json

client = anthropic.Anthropic()

TOOLS = [GITHUB_SEARCH_ISSUES_TOOL]
HANDLERS = {"search_github_issues": search_github_issues}

def run(user_prompt: str) -> str:
    messages = [{"role": "user", "content": user_prompt}]
    while True:
        resp = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            tools=TOOLS,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            return next(b.text for b in resp.content if b.type == "text")
        messages.append({"role": "assistant", "content": resp.content})
        results = []
        for block in resp.content:
            if block.type == "tool_use":
                handler = HANDLERS.get(block.name)
                if handler:
                    result = handler(**block.input)
                else:
                    result = {"error": "UNKNOWN_TOOL", "message": block.name, "retryable": False}
                results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": json.dumps(result),
                })
        messages.append({"role": "user", "content": results})

print(run("Find open issues about rate limiting in anthropics/anthropic-sdk-python"))
